mapper.update:
UPDATE OUT_OF_SCOPE_SERVICE
关联业务类型 = #{businessType}, 关联业务单号 = #{businessId}, 项目 = #{project}, 规格型号 = #{spec}, 单位 = #{unit}, 计划数量 = #{plannedQuantity}, 合同单价 = #{contractUnitPrice}, 对账结算数量 = #{settledQuantity}, 对账结算单价 = #{settledUnitPrice}, 对账结算金额 = #{settledAmount}, 状态 = #{status}, 是否锁定 = #{locked}, 锁定时间 = #{lockedAt}, 锁定人编码 = #{lockedBy}, 锁定原因 = #{lockReason}, 备注 = #{remark}, 更新时间 = NOW(), 更新人编码 = #{updatedBy} 更新人编码 = NULL
WHERE 价外费用编号 = #{outOfScopeServiceId}

mapper.select:
